'use strict';
function createDeployment(config) {
  const state = { phase: 'pending', version: config.version, canaries: [] };
  return {
    promote(target) {
      if (state.phase !== 'pending') throw new Error('already promoted');
      state.phase = 'canary';
      state.canaries.push({ target, deployedAt: Date.now() });
      return state;
    },
    fullRollout() {
      if (state.phase !== 'canary') throw new Error('must promote first');
      state.phase = 'full';
      state.rolloutAt = Date.now();
      return state;
    },
    getStatus() { return { ...state }; }
  };
}
module.exports = { createDeployment };
